 58	static void stm32_dcmi_process_dma_error(DCMI_HandleTypeDef *hdcmi)
 59	{
 60		struct video_stm32_dcmi_data *dev_data =
 61			CONTAINER_OF(hdcmi, struct video_stm32_dcmi_data, hdcmi);
 62	
 63		LOG_DBG("Restart DMA after Error!");
 64	
 65		/* Lets try to recover by stopping and restart */
 66		if (HAL_DCMI_Stop(&dev_data->hdcmi) != HAL_OK) {
 67			LOG_WRN("HAL_DCMI_Stop FAILED!");
 68			return;
 69		}
 70	
 71		if (HAL_DCMI_Start_DMA(&dev_data->hdcmi,
 72				       DCMI_MODE_CONTINUOUS,
 73				       (uint32_t)dev_data->vbuf->buffer,
 74				       dev_data->vbuf->size / 4) != HAL_OK) {
 75			LOG_WRN("Continuous: HAL_DCMI_Start_DMA FAILED!");
 76			return;
 77		}
 78	}
 79	
 80	void HAL_DCMI_ErrorCallback(DCMI_HandleTypeDef *hdcmi)
 81	{
 82		stm32_dcmi_process_dma_error(hdcmi);
 83	}
