 85	void HAL_DCMI_FrameEventCallback(DCMI_HandleTypeDef *hdcmi)
 86	{
 87		struct video_stm32_dcmi_data *dev_data =
 88				CONTAINER_OF(hdcmi, struct video_stm32_dcmi_data, hdcmi);
 89		struct video_buffer *vbuf;
 90		HAL_StatusTypeDef __maybe_unused hal_ret;
 91	
 92		hal_ret = HAL_DCMI_Suspend(hdcmi);
 93		__ASSERT_NO_MSG(hal_ret == HAL_OK);
 94	
 95		vbuf = k_fifo_get(&dev_data->fifo_in, K_NO_WAIT);
 96	
 97		if (vbuf == NULL) {
 98			LOG_DBG("Failed to get buffer from fifo");
 99			goto resume;
100		}
101	
102		vbuf->timestamp = k_uptime_get_32();
103		memcpy(vbuf->buffer, dev_data->vbuf->buffer, vbuf->bytesused);
104	
105		k_fifo_put(&dev_data->fifo_out, vbuf);
106	
107	resume:
108		hal_ret = HAL_DCMI_Resume(hdcmi);
109		__ASSERT_NO_MSG(hal_ret == HAL_OK);
110	}
