130	static int stm32_dma_init(const struct device *dev)
131	{
132		struct video_stm32_dcmi_data *data = dev->data;
133		struct stream *dma = &data->dma;
134		int ret;
135	
136		/* Check if the DMA device is ready */
137		if (!device_is_ready(dma->dma_dev)) {
138			LOG_ERR("%s DMA device not ready", dma->dma_dev->name);
139			return -ENODEV;
140		}
141	
142		/*
143		 * DMA configuration
144		 * Due to use of DMA HAL API in current driver,
145		 * both HAL and Zephyr DMA drivers should be configured.
146		 * The required configuration for Zephyr DMA driver should only provide
147		 * the minimum information to inform the DMA slot will be in used and
148		 * how to route callbacks.
149		 */
150		struct dma_config *dma_cfg = &dma->cfg;
151		static DMA_HandleTypeDef hdma;
152	
153		/* Proceed to the minimum Zephyr DMA driver init */
154		dma_cfg->user_data = &hdma;
155		/* HACK: This field is used to inform driver that it is overridden */
156		dma_cfg->linked_channel = STM32_DMA_HAL_OVERRIDE;
157		ret = dma_config(dma->dma_dev, dma->channel, dma_cfg);
158		if (ret != 0) {
159			LOG_ERR("Failed to configure DMA channel %d", dma->channel);
160			return ret;
161		}
162	
163		/*** Configure the DMA ***/
164		/* Set the parameters to be configured */
165		hdma.Init.Request		= DMA_REQUEST_DCMI;
166		hdma.Init.Direction		= DMA_PERIPH_TO_MEMORY;
167		hdma.Init.PeriphInc		= DMA_PINC_DISABLE;
168		hdma.Init.MemInc		= DMA_MINC_ENABLE;
169		hdma.Init.PeriphDataAlignment	= DMA_PDATAALIGN_WORD;
170		hdma.Init.MemDataAlignment	= DMA_MDATAALIGN_WORD;
171		hdma.Init.Mode			= DMA_CIRCULAR;
172		hdma.Init.Priority		= DMA_PRIORITY_HIGH;
173		hdma.Instance			= STM32_DMA_GET_INSTANCE(dma->reg, dma->channel);
174	#if defined(CONFIG_SOC_SERIES_STM32F7X) || defined(CONFIG_SOC_SERIES_STM32H7X)
175		hdma.Init.FIFOMode		= DMA_FIFOMODE_DISABLE;
176	#endif
177	
178		/* Initialize DMA HAL */
179		__HAL_LINKDMA(&data->hdcmi, DMA_Handle, hdma);
180	
181		if (HAL_DMA_Init(&hdma) != HAL_OK) {
182			LOG_ERR("DCMI DMA Init failed");
183			return -EIO;
184		}
185	
186		return 0;
187	}
