189	static int stm32_dcmi_enable_clock(const struct device *dev)
190	{
191		const struct video_stm32_dcmi_config *config = dev->config;
192		const struct device *dcmi_clock = DEVICE_DT_GET(STM32_CLOCK_CONTROL_NODE);
193	
194		/* Turn on DCMI peripheral clock */
195		return clock_control_on(dcmi_clock, (clock_control_subsys_t)&config->pclken);
196	}
